import { ChatMessage } from '../types';
import { MIMO_API_KEY, MIMO_API_BASE_URL, MIMO_MODEL } from '../constants';

export const sendChatRequest = async (messages: ChatMessage[]): Promise<string> => {
  try {
    // 1. 构造标准请求头
    const headers = {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${MIMO_API_KEY}`
    };

    // 2. 构造符合 MIMO 接口规范的请求体
    // (假设 MIMO 接口兼容通用的 Chat Completion 格式，如 OpenAI 规范)
    const requestBody = {
      model: MIMO_MODEL,
      messages: messages.map(msg => ({
        role: msg.role,
        content: msg.content
      })),
      temperature: 0.7,
      stream: false
    };

    console.log("正在呼叫海空智擎核心 (MIMO)...", { url: MIMO_API_BASE_URL, model: MIMO_MODEL });

    // 3. 发起真实的网络请求
    const response = await fetch(`${MIMO_API_BASE_URL}/chat/completions`, {
      method: 'POST',
      headers: headers,
      body: JSON.stringify(requestBody)
    });

    // 4. 处理 HTTP 错误状态
    if (!response.ok) {
      const errorText = await response.text();
      console.error(`MIMO API Error (${response.status}):`, errorText);
      throw new Error(`MIMO 服务端拒绝请求: ${response.status} ${response.statusText}`);
    }

    // 5. 解析响应数据
    const data = await response.json();

    // 校验返回结构 (兼容标准 choices[0].message.content 结构)
    if (data.choices && data.choices.length > 0 && data.choices[0].message) {
      return data.choices[0].message.content;
    } else {
      console.error('MIMO Response Format Mismatch:', data);
      return "错误：海空智擎核心返回的数据格式无法解析。";
    }

  } catch (error) {
    console.error("MIMO Connection Failed:", error);
    // 真实报错，不进行 Mock 掩盖
    return `[系统警告] 无法连接海空智擎核心 (MIMO)。\n\n原因: ${(error as Error).message}\n请检查 constants.ts 中的接口配置或网络连接。`;
  }
};

