const TabChat: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: 'MiMo 系统在线。等待指令...' }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Speech Recognition Ref
  const recognitionRef = useRef<any>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading, isListening]);

  // Initialize Speech Recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = false;
        recognitionRef.current.lang = 'zh-CN';
        recognitionRef.current.interimResults = false;

        recognitionRef.current.onresult = (event: any) => {
            const transcript = event.results[0][0].transcript;
            setInputValue(prev => prev + transcript);
            setIsListening(false);
        };

        recognitionRef.current.onerror = (event: any) => {
            console.error('Speech recognition error', event.error);
            setIsListening(false);
        };

        recognitionRef.current.onend = () => {
            setIsListening(false);
        };
    }
  }, []);

  const toggleVoiceInput = () => {
      if (isListening) {
          recognitionRef.current?.stop();
          setIsListening(false);
      } else {
          if (recognitionRef.current) {
            try {
                recognitionRef.current.start();
                setIsListening(true);
            } catch (e) {
                console.error(e);
            }
          } else {
              // Fallback simulation for browsers without support
              setIsListening(true);
              setTimeout(() => {
                  setInputValue("查询当前海域的风浪情况");
                  setIsListening(false);
              }, 1500);
          }
      }
  };

  const handleSend = async (textOverride?: string) => {
    const contentToSend = textOverride || inputValue;
    if (!contentToSend.trim()) return;

    const userMsg: ChatMessage = { role: 'user', content: contentToSend };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsLoading(true);

    try {
        // Strict match to user's Python SDK example
        const systemMsg: ChatMessage = {
             role: "system",
             content: "You are MiMo, an AI assistant developed by Xiaomi. Today is date: Tuesday, December 16, 2025. Your knowledge cutoff date is December 2024."
        };

        // Construct the full message chain
        const apiMessages = [systemMsg, ...messages.filter(m => m.role !== 'system'), userMsg];

        const aiResponseContent = await sendChatRequest(apiMessages);

        setMessages(prev => [...prev, { role: 'assistant', content: aiResponseContent }]);
    } catch (error) {
        // Show the RAW error message from the service
        setMessages(prev => [...prev, { role: 'assistant', content: `API 调用异常: ${(error as Error).message}` }]);
    } finally {
        setIsLoading(false);
    }
  };

  // --- Lightweight Markdown Renderer ---
