import { ChatMessage } from '../types';
import { MIMO_API_KEY, MIMO_API_BASE_URL, MIMO_MODEL } from '../constants';

export const sendChatRequest = async (messages: ChatMessage[]): Promise<string> => {
  // 1. Log the attempt
  console.log("--- MIMO API REQUEST START ---");
  console.log("URL:", `${MIMO_API_BASE_URL}/chat/completions`);
  console.log("Model:", MIMO_MODEL);
  console.log("Key (last 4):", MIMO_API_KEY.slice(-4));

  const requestBody = {
    model: MIMO_MODEL,
    messages: messages.map(msg => ({
      role: msg.role,
      content: msg.content
    })),
    max_completion_tokens: 1024,
    temperature: 0.3,
    top_p: 0.95,
    stream: false,
    frequency_penalty: 0,
    presence_penalty: 0,
    // extra_body mapped to root as per SDK behavior
    thinking: { type: "disabled" } 
  };

  console.log("Payload:", JSON.stringify(requestBody, null, 2));

  try {
    const response = await fetch(`${MIMO_API_BASE_URL}/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${MIMO_API_KEY}`
      },
      body: JSON.stringify(requestBody)
    });

    // 2. Check HTTP status first
    if (!response.ok) {
      const errorText = await response.text();
      console.error('MIMO API HTTP Error:', response.status, errorText);
      throw new Error(`Server Error ${response.status}: ${errorText}`);
    }

    // 3. Parse JSON
    const data = await response.json();
    console.log('MIMO API Success Response:', data);

    if (data.choices && data.choices.length > 0 && data.choices[0].message) {
      return data.choices[0].message.content;
    } else {
      console.error('Unexpected JSON structure:', data);
      throw new Error(`Invalid Response Structure: ${JSON.stringify(data)}`);
    }

  } catch (error) {
    // 4. Pass the raw error back to the UI
    console.error("MIMO API Request Failed:", error);
    throw error; 
  }
};

